}

function vanilla_h1() {
    'use strict';
    var result = document.getElementsByTagName("h1")[0].innerText;
    return result;
}

function xpath_h1() {
    'use strict';
    var xpathResult = document.evaluate('//h1[1]', document, null, XPathResult.ANY_TYPE, null);
    var result = xpathResult.iterateNext().innerText;
    return result;
}

